// ============================================
// HTML GENERATOR: SEO ENHANCED + SIMPLIFIED NAV
// ============================================

const item = $input.first().json;

// --- 1. ESTRAZIONE DATI ---
const htmlNode = item.Html || {}; 
const contentData = htmlNode.blog_content_structure || htmlNode.blog_content || {};
const ownerData = htmlNode.owner_data || item.owner_data || {};
const service = item.selected_service;

// Riferimento al Bot Telegram
const telegramBotUrl = `https://t.me/${item.owner_bot?.username || 'garofalo_ai_bot'}`;

// ID e Lingua
const fragmentId = item.user_request?.fragment_id || `post_${Date.now()}`;
const language = item.user_request?.lang || 'it';

// --- 2. GESTIONE IMMAGINE (CDN ASSOLUTO) ---
const imageFilename = `${fragmentId}.jpg`;
const cdnImageUrl = `https://minisite.trinai.it/minisite/${ownerData.vat_number.toUpperCase()}/images/${service.callback_data}.jpg`;;

// --- 3. SEO & METADATA (ENHANCED) ---
const seoData = contentData.seo || {};

// Fallback valori SEO
const metaTitle = seoData.meta_title || (contentData.hero?.title ? contentData.hero.title.substring(0, 60) : "Articolo Blog");
const metaDescription = seoData.meta_description || (contentData.hero?.subtitle ? contentData.hero.subtitle.substring(0, 155) : "Leggi questo contenuto.");
const keywords = seoData.keywords || "AI, Business, Innovazione";
const imageAlt = seoData.image_alt_text || "Immagine di copertina";

// Open Graph (con fallback)
const ogTitle = seoData.og_title || metaTitle;
const ogDescription = seoData.og_description || metaDescription;
const ogImage = seoData.og_image || cdnImageUrl;

// Canonical URL
const canonicalUrl = seoData.canonical_url || `${ownerData.website || 'https://trinaibos.com'}/blog/${seoData.slug || fragmentId}`;

// Twitter Card
const twitterCard = seoData.twitter_card || "summary_large_image";

// Author & Dates
const author = seoData.author || ownerData.company_name || "Redazione";
const authorUrl = seoData.author_url || ownerData.website;
const publishedDate = seoData.published_date || new Date().toISOString();
const modifiedDate = seoData.modified_date || publishedDate;

// Reading Time
const readingTime = seoData.reading_time_minutes || 8;

// Language & Topic
const langCode = seoData.language || language || 'it';
const primaryTopic = seoData.primary_topic || "Business";

// --- 4. SCHEMA.ORG: LOCAL BUSINESS ---
const localBusinessSchema = {
    "@context": "https://schema.org",
    "@type": "LocalBusiness",
    "name": ownerData.company_name || "Azienda",
    "image": cdnImageUrl,
    "telephone": ownerData.phone,
    "email": ownerData.email,
    "address": {
        "@type": "PostalAddress",
        "streetAddress": ownerData.address
    },
    "url": ownerData.website || "#"
};

// --- 5. SCHEMA.ORG: ARTICLE ---
const articleSchema = {
    "@context": "https://schema.org",
    "@type": seoData.schema_type || "BlogPosting",
    "headline": metaTitle,
    "description": metaDescription,
    "image": ogImage,
    "author": {
        "@type": "Organization",
        "name": author,
        "url": authorUrl
    },
    "publisher": {
        "@type": "Organization",
        "name": ownerData.company_name || author,
        "logo": {
            "@type": "ImageObject",
            "url": `${ownerData.website || 'https://trinaibos.com'}/logo.png`
        }
    },
    "datePublished": publishedDate,
    "dateModified": modifiedDate,
    "mainEntityOfPage": {
        "@type": "WebPage",
        "@id": canonicalUrl
    },
    "keywords": keywords,
    "articleSection": primaryTopic,
    "wordCount": contentData.hero?.title ? contentData.hero.title.split(' ').length * 50 : 2000,
    "timeRequired": `PT${readingTime}M`
};

// --- 6. SCHEMA.ORG: FAQ (se presenti) ---
let faqSchema = null;
if (contentData.faq && Array.isArray(contentData.faq) && contentData.faq.length > 0) {
    faqSchema = {
        "@context": "https://schema.org",
        "@type": "FAQPage",
        "mainEntity": contentData.faq.map(item => ({
            "@type": "Question",
            "name": item.question,
            "acceptedAnswer": {
                "@type": "Answer",
                "text": item.answer
            }
        }))
    };
}

// --- 7. BREADCRUMBS SCHEMA (mantenuto per SEO, non UI) ---
let breadcrumbSchema = null;
if (contentData.breadcrumbs && Array.isArray(contentData.breadcrumbs)) {
    breadcrumbSchema = {
        "@context": "https://schema.org",
        "@type": "BreadcrumbList",
        "itemListElement": contentData.breadcrumbs.map((crumb, index) => ({
            "@type": "ListItem",
            "position": index + 1,
            "name": crumb.name,
            "item": crumb.url === '#' ? canonicalUrl : (ownerData.website || 'https://trinaibos.com') + crumb.url
        }))
    };
}

// --- 8. HELPER FUNCTIONS ---
function escapeHtml(text) {
    if (!text) return '';
    return String(text)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
}

function renderParagraphs(paragraphs) {
    if (!paragraphs || !Array.isArray(paragraphs)) return '';
    return paragraphs.map(p => `<p>${escapeHtml(p)}</p>`).join('\n');
}

// Safety Check
if (!contentData.hero) {
    throw new Error("ERRORE: Dati 'hero' mancanti.");
}

// --- 9. FAQ HTML (se presenti) ---
let faqHtml = '';
if (contentData.faq && Array.isArray(contentData.faq) && contentData.faq.length > 0) {
    faqHtml = `
    <section class="faq-section">
        <h2>Domande Frequenti</h2>
        ${contentData.faq.map(item => `
            <div class="faq-item">
                <h3 class="faq-question">${escapeHtml(item.question)}</h3>
                <p class="faq-answer">${escapeHtml(item.answer)}</p>
            </div>
        `).join('')}
    </section>`;
}

// --- 10. TEMPLATE HTML ---
const htmlTemplate = `<!DOCTYPE html>
<html lang="${langCode}">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">

    <!-- SEO METADATA ENHANCED -->
    <title>${escapeHtml(metaTitle)}</title>
    <meta name="description" content="${escapeHtml(metaDescription)}">
    <meta name="keywords" content="${escapeHtml(keywords)}">
    <meta name="author" content="${escapeHtml(author)}">
    <meta name="robots" content="index, follow, max-image-preview:large, max-snippet:-1, max-video-preview:-1">
    <link rel="canonical" href="${canonicalUrl}">

    <!-- HREFLANG (se multilingua) -->
    ${langCode === 'it' ? '<link rel="alternate" hreflang="it" href="' + canonicalUrl + '">' : ''}

    <!-- OPEN GRAPH (ENHANCED) -->
    <meta property="og:type" content="article">
    <meta property="og:title" content="${escapeHtml(ogTitle)}">
    <meta property="og:description" content="${escapeHtml(ogDescription)}">
    <meta property="og:image" content="${ogImage}">
    <meta property="og:image:alt" content="${escapeHtml(imageAlt)}">
    <meta property="og:image:width" content="1200">
    <meta property="og:image:height" content="630">
    <meta property="og:url" content="${canonicalUrl}">
    <meta property="og:site_name" content="${escapeHtml(ownerData.company_name || 'Blog')}">
    <meta property="og:locale" content="${langCode}_${langCode.toUpperCase()}">
    <meta property="article:published_time" content="${publishedDate}">
    <meta property="article:modified_time" content="${modifiedDate}">
    <meta property="article:author" content="${escapeHtml(author)}">
    <meta property="article:section" content="${escapeHtml(primaryTopic)}">
    ${seoData.entity_mentions ? seoData.entity_mentions.map(entity => 
        `<meta property="article:tag" content="${escapeHtml(entity)}">`
    ).join('\n    ') : ''}

    <!-- TWITTER CARD (ENHANCED) -->
    <meta name="twitter:card" content="${twitterCard}">
    <meta name="twitter:title" content="${escapeHtml(ogTitle)}">
    <meta name="twitter:description" content="${escapeHtml(ogDescription)}">
    <meta name="twitter:image" content="${ogImage}">
    <meta name="twitter:image:alt" content="${escapeHtml(imageAlt)}">
    ${ownerData.twitter_handle ? `<meta name="twitter:site" content="@${ownerData.twitter_handle}">` : ''}

    <!-- SCHEMA.ORG: LOCAL BUSINESS -->
    <script type="application/ld+json">
    ${JSON.stringify(localBusinessSchema, null, 2)}
    </script>

    <!-- SCHEMA.ORG: ARTICLE -->
    <script type="application/ld+json">
    ${JSON.stringify(articleSchema, null, 2)}
    </script>

    ${faqSchema ? `<!-- SCHEMA.ORG: FAQ -->
    <script type="application/ld+json">
    ${JSON.stringify(faqSchema, null, 2)}
    </script>` : ''}

    ${breadcrumbSchema ? `<!-- SCHEMA.ORG: BREADCRUMBS -->
    <script type="application/ld+json">
    ${JSON.stringify(breadcrumbSchema, null, 2)}
    </script>` : ''}

    <!-- FONTS -->
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600;700;900&display=swap" rel="stylesheet">

    <style>
        :root {
            --color-primary: #1F2754; 
            --color-accent: #A58EEB;
            --color-text: #212529; 
            --color-light-bg: #f9f9f9;
            --color-white: #ffffff;
        }

        * { box-sizing: border-box; }

        body {
            font-family: 'Inter', sans-serif;
            line-height: 1.6;
            color: var(--color-text);
            margin: 0;
            background-color: var(--color-white);
        }

        /* --- NAVBAR SEMPLIFICATA --- */
        .navbar {
            background-color: var(--color-white);
            border-bottom: 1px solid #eee;
            padding: 15px 0;
            position: sticky;
            top: 0;
            z-index: 1000;
        }

        .nav-container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 0 20px;
            display: flex;
            align-items: center;
        }

        .brand-name {
            font-weight: 700;
            font-size: 1.2rem;
            color: var(--color-primary);
            text-decoration: none;
            transition: color 0.3s ease;
        }

        .brand-name:hover {
            color: var(--color-accent);
        }

        /* --- READING TIME BADGE --- */
        .reading-time {
            display: inline-block;
            background: var(--color-light-bg);
            color: #666;
            padding: 6px 12px;
            border-radius: 20px;
            font-size: 0.8rem;
            margin-bottom: 20px;
        }

        /* --- HERO SECTION --- */
        .hero {
            min-height: 60vh; 
            padding: 80px 20px;
            background-size: cover;
            background-position: center;
            display: flex;
            align-items: center;
            justify-content: center;
            position: relative;
            color: var(--color-white);
            text-align: center;
        }

        .hero-overlay {
            position: absolute;
            top: 0; left: 0; right: 0; bottom: 0;
            background-color: rgba(31, 39, 84, 0.85);
            z-index: 1;
        }

        .hero-content {
            position: relative;
            z-index: 2;
            max-width: 800px;
            width: 100%;
        }

        .hero h1 {
            font-size: clamp(1.8rem, 4vw, 2.8rem);
            font-weight: 900;
            margin-bottom: 1.5rem;
            line-height: 1.3;
            text-shadow: 0 2px 4px rgba(0,0,0,0.3);
        }

        .hero p {
            font-size: clamp(1rem, 2.5vw, 1.25rem);
            font-weight: 300;
            opacity: 0.95;
            margin-bottom: 35px;
            line-height: 1.6;
        }

        /* --- BUTTONS --- */
        .cta-button {
            display: inline-block;
            padding: 16px 32px;
            background-color: var(--color-accent);
            color: white;
            font-size: 1.1rem;
            font-weight: 700;
            text-decoration: none;
            border-radius: 50px;
            transition: all 0.3s ease;
            box-shadow: 0 4px 15px rgba(165, 142, 235, 0.4);
        }

        .cta-button:hover {
            background-color: white;
            color: var(--color-primary);
            transform: translateY(-2px);
        }

        .cta-block .cta-button:hover {
            background-color: var(--color-primary);
            color: white;
        }

        /* --- CONTENT --- */
        .article-container {
            max-width: 800px;
            margin: 60px auto;
            padding: 0 24px;
        }

        .article-content h2 {
            color: var(--color-primary);
            margin-top: 3rem;
            margin-bottom: 1.5rem;
            font-size: clamp(1.5rem, 3vw, 2rem);
            font-weight: 700;
            line-height: 1.3;
        }

        .article-content h3 {
             color: var(--color-primary);
             font-size: 1.3rem;
             margin-top: 2rem;
             font-weight: 600;
        }

        .article-content p {
            margin-bottom: 1.5rem;
            font-size: 1.1rem;
            color: #333;
        }

        blockquote {
            border-left: 5px solid var(--color-accent);
            padding: 20px 25px;
            margin: 30px 0;
            background-color: #f8f9fa;
            font-style: italic;
            color: #555;
            font-size: 1.1rem;
        }

        /* --- TABLE --- */
        table {
            width: 100%;
            border-collapse: collapse;
            margin: 30px 0;
            box-shadow: 0 4px 6px rgba(0,0,0,0.05);
            font-size: 0.9rem;
        }

        th, td { padding: 12px 15px; }

        th {
            background-color: var(--color-primary);
            color: white;
            text-align: left;
        }

        td {
            border-bottom: 1px solid #eee;
            color: #444;
        }

        tr:nth-child(even) { background-color: #f9f9f9; }
        td strong { color: var(--color-primary); }

        /* --- FAQ SECTION --- */
        .faq-section {
            max-width: 800px;
            margin: 60px auto;
            padding: 40px 24px;
            background: var(--color-light-bg);
            border-radius: 12px;
        }

        .faq-item {
            margin-bottom: 30px;
            padding-bottom: 20px;
            border-bottom: 1px solid #ddd;
        }

        .faq-item:last-child {
            border-bottom: none;
        }

        .faq-question {
            color: var(--color-primary);
            font-size: 1.2rem;
            font-weight: 600;
            margin-bottom: 10px;
        }

        .faq-answer {
            color: #555;
            line-height: 1.6;
        }

        /* --- CTA BLOCK --- */
        .cta-block {
            text-align: center;
            padding: 50px 20px;
            margin: 60px 0;
            background: linear-gradient(135deg, #f8f9fa 0%, #eef1f5 100%);
            border-radius: 12px;
            box-shadow: 0 10px 25px rgba(0,0,0,0.05);
        }

        .urgency-text {
            color: #d63031;
            font-weight: 700;
            margin-bottom: 15px;
            display: inline-block;
            text-transform: uppercase;
            font-size: 0.85rem;
            letter-spacing: 1px;
        }

        /* --- FOOTER --- */
        footer {
            text-align: center;
            padding: 50px 20px;
            margin-top: 80px;
            border-top: 1px solid #eee;
            background-color: #f8f9fa;
            color: #666;
            font-size: 0.9rem;
        }

        footer a { color: var(--color-primary); text-decoration: none; font-weight: 600; }

        @media (max-width: 768px) {
            .hero { padding: 60px 20px; }
            .cta-button { width: 100%; text-align: center; }
            table { display: block; overflow-x: auto; white-space: nowrap; }
            .article-container { padding: 0 20px; margin: 40px auto; }
        }
    </style>
</head>
<body>

    <!-- NAV SEMPLIFICATA -->
    <header class="navbar">
        <div class="nav-container">
            <a href="${ownerData.website || '/'}" class="brand-name">${escapeHtml(ownerData.company_name)}</a>
        </div>
    </header>

    <!-- HERO SECTION -->
    <section class="hero" style="background-image: url('${cdnImageUrl}');">
        <div class="hero-overlay"></div>
        <div class="hero-content">
            <h1>${escapeHtml(contentData.hero.title)}</h1>
            <p>${escapeHtml(contentData.hero.subtitle)}</p>

            <a href="${telegramBotUrl}" class="cta-button">
                ${escapeHtml(contentData.hero.cta_text)}
            </a>

            <p style="font-size: 0.85rem; margin-top: 20px; opacity: 0.8;">
                ${escapeHtml(contentData.hero.risk_reversal)}
            </p>
        </div>
    </section>

    <!-- CONTENT -->
    <main class="article-container">
        <div class="reading-time">
            ⏱️ Tempo di lettura: ~${readingTime} minuti
        </div>

        <article class="article-content">

            <h2>${escapeHtml(contentData.problem.title)}</h2>
            ${renderParagraphs(contentData.problem.paragraphs)}
            ${contentData.problem.quote ? `<blockquote>${escapeHtml(contentData.problem.quote)}</blockquote>` : ''}

            <h2>${escapeHtml(contentData.solution.title)}</h2>
            ${renderParagraphs(contentData.solution.paragraphs)}

            ${contentData.solution.subsection ? `
            <h3>${escapeHtml(contentData.solution.subsection.title)}</h3>
            ${renderParagraphs(contentData.solution.subsection.paragraphs)}
            ` : ''}

            <h2>${escapeHtml(contentData.authority.title)}</h2>
            ${renderParagraphs(contentData.authority.paragraphs)}

            <h2>${escapeHtml(contentData.comparison.title)}</h2>
            <p>${escapeHtml(contentData.comparison.intro)}</p>
            ${contentData.comparison.table_html}

            <div class="cta-block">
                ${contentData.cta_final.urgency ? `<span class="urgency-text">🔥 ${escapeHtml(contentData.cta_final.urgency)}</span>` : ''}
                <h2>${escapeHtml(contentData.cta_final.title)}</h2>
                ${renderParagraphs(contentData.cta_final.paragraphs)}
                <br>
                <a href="${telegramBotUrl}" class="cta-button">
                    ${escapeHtml(contentData.cta_final.button_text)}
                </a>
                <p style="margin-top:20px; font-size:0.9rem; font-style:italic;">
                    ${escapeHtml(contentData.cta_final.risk_reversal)}
                </p>
            </div>

        </article>
    </main>

    <!-- FAQ SECTION -->
    ${faqHtml}

    <!-- FOOTER -->
    <footer>
        <small>
            <strong>${escapeHtml(ownerData.company_name)}</strong><br>
            ${ownerData.vat_number ? `P.IVA: ${escapeHtml(ownerData.vat_number)}<br>` : ''}
            ${ownerData.address ? `Sede: ${escapeHtml(ownerData.address)}<br>` : ''}
            ${ownerData.email ? `Contatti: ${escapeHtml(ownerData.email)}` : ''}
            ${ownerData.phone ? ` - ${escapeHtml(ownerData.phone)}` : ''}<br>
            <br>
            ${ownerData.website ? `<a href="${ownerData.website}" target="_blank">Visita il Sito Ufficiale</a>` : ''}
        </small>
    </footer>

</body>
</html>`;

// --- 11. OUTPUT ---
return [{
    json: {
        html_content: htmlTemplate,
        filename: `${fragmentId}.html`,
        seo_data: {
            ...seoData,
            canonical_url: canonicalUrl,
            og_title: ogTitle,
            og_description: ogDescription,
            og_image: ogImage
        },
        social_media: item.Html.social_media,
        image_url_used: cdnImageUrl,
        schemas_generated: {
            article: !!articleSchema,
            faq: !!faqSchema,
            breadcrumb: !!breadcrumbSchema,
            local_business: !!localBusinessSchema
        },
        ...item
    }
}];

const input = items[0].json;

// 1. Estrazione ID SVC
const callbackData = input.body.callback_query.data;
const svcId = callbackData.split('sap_')[1]; 

// 2. Recupero dati servizio dal catalogo
let selectedService = null;
const categories = input.service_catalog_setup.categories || [];

for (const cat of categories) {
  const match = cat.subcategories.find(s => s.callback_data === svcId);
  if (match) {
    selectedService = {
      ...match,
      category_name: cat.name
    };
    break;
  }
}

// 3. Ritorno SOLO i blocchi richiesti + il servizio estratto
return {
  HoneyPot: input.HoneyPot,
  owner_data: input.owner_data,
  body: input.body,
  selected_service: selectedService
};

