const item = $input.first().json;
const svcId = item.selected_service?.callback_data || "unknown";
const serviceName = item.selected_service?.name || "Servizio";

const msgText = `
⚠️ <b>ANALISI STRATEGICA SOSPESA</b>
━━━━━━━━━━━━━━━━━━━━
Il sistema ha riscontrato un'incongruenza durante l'analisi per:
📦 <b>${serviceName}</b>

📌 <b>Cosa è successo:</b>
├ <b>Stato:</b> Elaborazione interrotta
└ <b>Causa:</b> L'AI non è riuscita a definire i punti di forza psicologici per questa specifica configurazione.

<i>Non posso procedere alla creazione della pagina senza una strategia persuasiva solida. Per favore, riavvia il processo.</i>
━━━━━━━━━━━━━━━━━━━━
`;

return [{ json: { 
    ...item, 
    telegramApiPayload: {
        method: "editMessageText", 
        chat_id: item.owner_data.chat_id, 
        message_id: item.body.callback_query.message.message_id,
        text: msgText, 
